import strawberry
from sqlalchemy import create_engine, Column, Integer, String, ForeignKey, Text
from sqlalchemy.orm import relationship, sessionmaker, declarative_base
from typing import List

Base = declarative_base()
engine = create_engine('sqlite:///example.db')
Session = sessionmaker(bind=engine)
session = Session()

class ProductModel(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    category_id = Column(Integer, ForeignKey('categories.id'))
    seller_id = Column(Integer, ForeignKey('sellers.id'))
    images = relationship("ImageModel", back_populates="product")
    reviews = relationship("ReviewModel", back_populates="product")

class CategoryModel(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True)
    name = Column(String)

class SellerModel(Base):
    __tablename__ = 'sellers'
    id = Column(Integer, primary_key=True)
    name = Column(String)

class ImageModel(Base):
    __tablename__ = 'images'
    id = Column(Integer, primary_key=True)
    url = Column(String)
    product_id = Column(Integer, ForeignKey('products.id'))
    product = relationship("ProductModel", back_populates="images")

class ReviewModel(Base):
    __tablename__ = 'reviews'
    id = Column(Integer, primary_key=True)
    content = Column(Text)
    product_id = Column(Integer, ForeignKey('products.id'))
    product = relationship("ProductModel", back_populates="reviews")

Base.metadata.create_all(engine)

@strawberry.type
class Review:
    id: int
    content: str

@strawberry.type
class Image:
    id: int
    url: str

@strawberry.type
class Seller:
    id: int
    name: str

@strawberry.type
class Category:
    id: int
    name: str

@strawberry.type
class Product:
    id: int
    name: str
    category: Category
    seller: Seller
    images: List[Image]
    reviews: List[Review]

@strawberry.type
class Query:
    @strawberry.field
    def products(self) -> List[Product]:
        products = session.query(ProductModel).all()
        return [
            Product(
                id=p.id,
                name=p.name,
                category=Category(id=p.category.id, name=p.category.name),
                seller=Seller(id=p.seller.id, name=p.seller.name),
                images=[Image(id=i.id, url=i.url) for i in p.images],
                reviews=[Review(id=r.id, content=r.content) for r in p.reviews]
            ) for p in products
        ]

schema = strawberry.Schema(query=Query)